+      <AnimatePresence mode="popLayout">
+        {toasts.map((t) => (
+          <ToastItem
+            key={t.id}
+            toast={t}
+            onDismiss={() => toastStore.remove(t.id)}
+          />
+        ))}
+      </AnimatePresence>
+    </div>
+  );
+}

